#include <stdio.h>
int main() {
    int n, count = 0;
    scanf("%d", &n);
    for (int i = 0; i < n; i++) {
        int x;
        scanf("%d", &x);
        if (x % 2 != 0) count++;
    }
    if (count % 2 == 0) printf("Ehab");
    else printf("Mahmoud");
    return 0;
}

