code.JavaScript:
const readline = require('readline').createInterface({ input: process.stdin, output: process.stdout });
let i = 0;
let count = 0;
let n;
readline.on('line', line => {
    if (i == 0) {
        n = parseInt(line);
        i++;
    } else {
        let arr = line.split(' ').map(x => parseInt(x));
        arr.forEach(x => {
            if (x % 2 != 0) count++;
        });
        if (count % 2 == 0) console.log("Ehab");
        else console.log("Mahmoud");
        readline.close();
    }
});
